import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        Encoder encoder = ESAPI.encoder();
        String safeUserInput = encoder.encodeForHTML(userInput);

        try (PrintWriter out = new PrintWriter(new FileWriter("output.html"))) {
            out.println("<html>");
            out.println("<head><title>XSS Safe Page</title></head>");
            out.println("<body>");
            out.println("User Input: " + safeUserInput); // Properly handling user input
            out.println("</body>");
            out.println("</html>");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
